package v1beta1

import (
	"context"
	"testing"

	"github.com/openshift/multiarch-tuning-operator/api/common/plugins"
)

func TestClusterPodPlacementConfigValidator_validate(t *testing.T) {
	tests := []struct {
		name    string
		cppc    *ClusterPodPlacementConfig
		wantErr bool
	}{
		{
			name: "nil plugins passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{},
			},
			wantErr: false,
		},
		{
			name: "nil nodeAffinityScoring passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{},
				},
			},
			wantErr: false,
		},
		{
			name: "unique architectures pass validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "single architecture passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 100},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "duplicate architectures fail validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
		{
			name: "duplicate among multiple architectures fails validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
	}

	v := &ClusterPodPlacementConfigValidator{}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateCreate(context.Background(), tt.cppc)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateCreate() error = %v, wantErr %v", err, tt.wantErr)
			}
			_, err = v.ValidateUpdate(context.Background(), nil, tt.cppc)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateUpdate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}
